//! Real FLUX MMDiT velocity prediction + flow-match scheduler + VAE decode.
//!
//! This module replaces the procedural "carrier painter" with the actual FLUX
//! diffusion graph: timestep/pooled conditioning, EmbedND rotary positions over
//! the concatenated [text‖image] token stream, the 19 double-stream (MMDiT)
//! blocks, the 38 single-stream blocks, the AdaLN-out final projection, a
//! flow-match Euler scheduler, and the full AutoencoderKL decoder.
//!
//! All weights are loaded from the flux-1-schnell KNOT (Q8_0 linears, F32
//! norms/conv-out). The compute here is pure CPU f32. It is sovereign: no
//! third-party inference, no paid AI.
//!
//! Correctness here rests on FLUX reference semantics (BFL/diffusers) and visual
//! inspection of the produced PNGs; without torch/diffusers installed we do NOT
//! have a numeric reference cross-check.

#![cfg(not(target_arch = "wasm32"))]

use crate::loader::{fetch_knot_tensor_bytes_from_metadata, KnotWeights, OwnedBytes};
use crate::math::{dot_product, gelu_inplace, mat_vec_q8_0, mat_vec_q8_0_rows_shared, softmax};

pub const FLUX_DIT_HIDDEN: usize = 3072;
pub const FLUX_DIT_HEADS: usize = 24;
pub const FLUX_DIT_HEAD_DIM: usize = 128;
pub const FLUX_DIT_MLP: usize = 12288;
pub const FLUX_IN_CHANNELS: usize = 64; // 16 latent * 2 * 2 patch
pub const FLUX_TXT_DIM: usize = 4096;
pub const FLUX_POOL_DIM: usize = 768;
pub const FLUX_NUM_DOUBLE: usize = 19;
pub const FLUX_NUM_SINGLE: usize = 38;
pub const FLUX_LATENT_CHANNELS: usize = 16;
pub const FLUX_TIME_EMB_DIM: usize = 256;
const QK_NORM_EPS: f32 = 1e-6;
const ADALN_EPS: f32 = 1e-6;
// EmbedND axis dims for FLUX: [time/0, height, width] = 16 + 56 + 56 = 128 head_dim.
const ROPE_AXES: [usize; 3] = [16, 56, 56];
const ROPE_THETA: f32 = 10_000.0;

// ─────────────────────────── small math helpers ───────────────────────────

/// Flushed marker for the DiT forward entry, so a silent hang/OOM inside the
/// first velocity pass (patchify, rope, block 0) is pinpointed line-by-line.
/// Gated on FLUX_DIT_TRACE!=0 (default ON) and only fires on the first pass via
/// the caller passing `enabled`.
#[inline]
fn dit_marker(marker: &str) {
    use std::io::Write;
    eprintln!("[dit] {marker}");
    let _ = std::io::stderr().flush();
}

#[inline]
fn silu(x: f32) -> f32 {
    x / (1.0 + (-x).exp())
}

fn silu_inplace(v: &mut [f32]) {
    for x in v.iter_mut() {
        *x = silu(*x);
    }
}

/// out[r] = sum_c w[r,c] * x[c] + b[r], with Q8_0 weight rows.
fn q8_linear(out: &mut [f32], x: &[f32], w: &[u8], bias: &[f32], rows: usize, cols: usize) {
    debug_assert_eq!(x.len(), cols);
    debug_assert_eq!(out.len(), rows);
    mat_vec_q8_0(out, x, w, rows, cols);
    for (o, b) in out.iter_mut().zip(bias.iter()) {
        *o += *b;
    }
}

/// LayerNorm with no learnable affine (FLUX uses elementwise_affine=False inside
/// the modulated blocks; the scale/shift come from AdaLN modulation).
fn layernorm_no_affine(v: &mut [f32]) {
    let n = v.len() as f32;
    let mean = v.iter().sum::<f32>() / n;
    let var = v.iter().map(|x| (x - mean) * (x - mean)).sum::<f32>() / n;
    let inv = 1.0 / (var + ADALN_EPS).sqrt();
    for x in v.iter_mut() {
        *x = (*x - mean) * inv;
    }
}

/// Per-head RMS norm in place over one token's head slice [head_dim].
fn rms_norm_head(head: &mut [f32], scale: &[f32]) {
    let n = head.len() as f32;
    let ms = head.iter().map(|x| x * x).sum::<f32>() / n;
    let inv = 1.0 / (ms + QK_NORM_EPS).sqrt();
    for (x, s) in head.iter_mut().zip(scale.iter()) {
        *x = *x * inv * *s;
    }
}

// ─────────────────────────── tensor fetch ───────────────────────────

#[allow(dead_code)]
fn fetch_q8(knot_source: &str, knot: &KnotWeights, name: &str) -> Result<Vec<u8>, String> {
    let t = fetch_knot_tensor_bytes_from_metadata(
        knot_source,
        &knot.metadata,
        knot.payload_offset,
        name,
    )
    .map_err(|e| format!("fetch {name}: {e}"))?;
    if !t.info.tensor_type.eq_ignore_ascii_case("Q8_0") {
        return Err(format!("{name} must be Q8_0, got {}", t.info.tensor_type));
    }
    Ok(t.bytes)
}

/// Zero-copy Q8_0 fetch: returns an [`OwnedBytes`] that, for a local mmap-backed
/// knot, is a borrowed slice into the file mapping (NO resident heap copy). The
/// 12.6 GB of DiT Q8 weights stay file-backed/demand-paged this way — the OS
/// pages in only the working set and discards clean read-only pages instead of
/// swapping anonymous heap. Falls back to an owned `Vec<u8>` for HTTP/rknot
/// backends (which already buffer in heap). The dequant math reads the SAME Q8
/// bytes via `Deref<Target=[u8]>`, so correctness is identical.
fn fetch_q8_bytes(knot_source: &str, knot: &KnotWeights, name: &str) -> Result<OwnedBytes, String> {
    let info = knot
        .metadata
        .get(name)
        .ok_or_else(|| format!("fetch {name}: missing tensor"))?;
    if !info.tensor_type.eq_ignore_ascii_case("Q8_0") {
        return Err(format!("{name} must be Q8_0, got {}", info.tensor_type));
    }

    // Preferred path: resolve a zero-copy slice directly against the knot's own
    // mmap (Arc<Mmap> + offset/len). No resident heap copy — the page cache
    // owns the bytes and the OS discards clean read-only pages under pressure.
    if let Some(mmap) = knot.mmap.as_ref() {
        let start = knot
            .payload_offset
            .checked_add(info.offset as usize)
            .ok_or_else(|| format!("tensor {name} range start overflows usize"))?;
        let end = start
            .checked_add(info.length as usize)
            .ok_or_else(|| format!("tensor {name} range end overflows usize"))?;
        if end > mmap.len() {
            return Err(format!("tensor {name} range {start}..{end} exceeds mmap len {}", mmap.len()));
        }
        return Ok(OwnedBytes::Mmap {
            mmap: std::sync::Arc::clone(mmap),
            start,
            end,
        });
    }

    // Next: the backend may itself be mmap-backed (MmapBackend) and return a
    // zero-copy OwnedBytes::Mmap; HTTP/rknot backends return an owned buffer.
    if let Ok(bytes) = knot.backend.fetch_tensor(name) {
        return Ok(bytes);
    }

    // Last resort (metadata-only knot with no mmap, no serving backend): read
    // the single tensor from the file by path into an owned buffer. This is the
    // old behavior and still copies — but only for this fallback configuration.
    let t = fetch_knot_tensor_bytes_from_metadata(
        knot_source,
        &knot.metadata,
        knot.payload_offset,
        name,
    )
    .map_err(|e| format!("fetch {name}: {e}"))?;
    Ok(OwnedBytes::Owned(std::sync::Arc::new(t.bytes)))
}

fn fetch_f32(knot_source: &str, knot: &KnotWeights, name: &str) -> Result<Vec<f32>, String> {
    let t = fetch_knot_tensor_bytes_from_metadata(
        knot_source,
        &knot.metadata,
        knot.payload_offset,
        name,
    )
    .map_err(|e| format!("fetch {name}: {e}"))?;
    if !t.info.tensor_type.eq_ignore_ascii_case("F32")
        && !t.info.tensor_type.eq_ignore_ascii_case("fp32")
    {
        return Err(format!("{name} must be F32, got {}", t.info.tensor_type));
    }
    let n = t.bytes.len() / 4;
    let mut out = vec![0.0f32; n];
    for (i, chunk) in t.bytes.chunks_exact(4).enumerate() {
        out[i] = f32::from_le_bytes([chunk[0], chunk[1], chunk[2], chunk[3]]);
    }
    Ok(out)
}

/// A Q8_0 weight + F32 bias linear layer.
///
/// `w` is an [`OwnedBytes`]: for a local mmap-backed knot it is a zero-copy
/// borrowed slice into the file mapping (Arc<Mmap> + offset/len), so the DiT's
/// ~12.6 GB of Q8 weights are NOT copied into resident anonymous heap — they
/// stay file-backed and demand-paged. The matmul kernels read `&self.w[..]`
/// (`OwnedBytes: Deref<Target=[u8]>`), identical bytes to the old `Vec<u8>`.
struct Linear {
    w: OwnedBytes,
    b: Vec<f32>,
    rows: usize,
    cols: usize,
    /// When true and `FLUX_SPEC_DEQUANT` is set, `apply_batch` routes through the
    /// per-tile speculative-dequant matmul (`flux_spec_dequant`) and accumulates
    /// the op-level admit rate into the global render counters. Only the chosen
    /// heavy layer (block-0 `img_fc1`) is tagged.
    spec_target: bool,
}

impl Linear {
    fn load(
        knot_source: &str,
        knot: &KnotWeights,
        weight_name: &str,
        bias_name: &str,
        rows: usize,
        cols: usize,
    ) -> Result<Self, String> {
        Ok(Self {
            w: fetch_q8_bytes(knot_source, knot, weight_name)?,
            b: fetch_f32(knot_source, knot, bias_name)?,
            rows,
            cols,
            spec_target: false,
        })
    }
    fn apply(&self, x: &[f32]) -> Vec<f32> {
        let mut out = vec![0.0f32; self.rows];
        q8_linear(&mut out, x, &self.w[..], &self.b, self.rows, self.cols);
        out
    }

    /// Batched apply over `tokens` inputs of length `cols`, packed flat
    /// [tokens*cols] -> flat [tokens*rows]. Bias added per row.
    fn apply_batch(&self, xs: &[f32], tokens: usize) -> Vec<f32> {
        let mut out = vec![0.0f32; tokens * self.rows];
        let cfg = crate::flux_spec_dequant::spec_runtime_config();
        if self.spec_target && cfg.enabled {
            // Per-tile speculative dequant on this heavy DiT linear. Missed tiles
            // refine to the lattice nearest point; admitted tiles keep coarse Q8.
            let rep = crate::flux_spec_dequant::render_spec_matmul(
                &mut out, xs, &self.w[..], self.rows, self.cols, tokens, cfg,
            );
            eprintln!(
                "[flux-spec] {} matmul: {} tiles, {} admit ({:.1}%), γ={:.3}",
                cfg.lattice.name(),
                rep.tiles,
                rep.admitted,
                100.0 * rep.admit_rate(),
                cfg.gamma
            );
        } else {
            mat_vec_q8_0_rows_shared(&mut out, xs, &self.w[..], self.rows, self.cols, tokens);
        }
        for t in 0..tokens {
            let o = t * self.rows;
            for r in 0..self.rows {
                out[o + r] += self.b[r];
            }
        }
        out
    }
}

// ─────────────────────────── EmbedND RoPE ───────────────────────────

/// Per-token rotary table: for each token, head_dim/2 (cos,sin) pairs built from
/// 3 axes (dim 16+56+56 = 64 pairs). Text tokens sit at position 0 on all axes;
/// image tokens sit at (0, row, col) over the latent_h x latent_w patch grid.
struct RopeTable {
    // cos[token * 64 + pair], sin[token * 64 + pair]; 64 = head_dim/2
    cos: Vec<f32>,
    sin: Vec<f32>,
    tokens: usize,
    pairs: usize,
}

impl RopeTable {
    fn build(text_len: usize, latent_h: usize, latent_w: usize) -> Self {
        let pairs: usize = ROPE_AXES.iter().sum::<usize>() / 2; // 64
        let img_len = latent_h * latent_w;
        let tokens = text_len + img_len;
        let mut cos = vec![1.0f32; tokens * pairs];
        let mut sin = vec![0.0f32; tokens * pairs];
        // Per-axis frequencies. For axis with dim d (number of components, even),
        // there are d/2 freq pairs; omega_k = theta^(-2k/d), k in 0..d/2.
        let axis_pairs: Vec<usize> = ROPE_AXES.iter().map(|d| d / 2).collect();
        for tok in 0..tokens {
            // positions on the 3 axes
            let pos: [f32; 3] = if tok < text_len {
                [0.0, 0.0, 0.0]
            } else {
                let p = tok - text_len;
                let row = (p / latent_w) as f32;
                let col = (p % latent_w) as f32;
                [0.0, row, col]
            };
            let mut pair_off = 0usize;
            for (axis, &d) in ROPE_AXES.iter().enumerate() {
                let half = d / 2;
                for k in 0..half {
                    let omega = ROPE_THETA.powf(-(2.0 * k as f32) / d as f32);
                    let angle = pos[axis] * omega;
                    let idx = tok * pairs + pair_off + k;
                    cos[idx] = angle.cos();
                    sin[idx] = angle.sin();
                }
                pair_off += half;
            }
            let _ = &axis_pairs; // documented layout
        }
        RopeTable {
            cos,
            sin,
            tokens,
            pairs,
        }
    }

    /// Apply rotary to one token's full hidden vector (heads*head_dim), in place.
    /// FLUX rotates consecutive pairs (x0,x1),(x2,x3)... within each head using the
    /// per-pair (cos,sin); the same 64 pairs apply to every head.
    fn apply_token(&self, hidden: &mut [f32], token: usize) {
        debug_assert_eq!(hidden.len(), FLUX_DIT_HIDDEN);
        let base = token * self.pairs;
        for head in 0..FLUX_DIT_HEADS {
            let ho = head * FLUX_DIT_HEAD_DIM;
            for pair in 0..self.pairs {
                let c = self.cos[base + pair];
                let s = self.sin[base + pair];
                let i0 = ho + 2 * pair;
                let i1 = i0 + 1;
                let x0 = hidden[i0];
                let x1 = hidden[i1];
                hidden[i0] = x0 * c - x1 * s;
                hidden[i1] = x0 * s + x1 * c;
            }
        }
    }
}

// ─────────────────────────── attention ───────────────────────────

/// Full (non-causal) multi-head attention over a joined stream of `tokens`
/// tokens, each FLUX_DIT_HIDDEN wide. q/k/v are [tokens * hidden]. Output is
/// [tokens * hidden].
fn joint_attention(q: &[f32], k: &[f32], v: &[f32], tokens: usize) -> Result<Vec<f32>, String> {
    use gnosis_frf::prelude::*;
    let mut out = vec![0.0f32; tokens * FLUX_DIT_HIDDEN];
    let scale = 1.0 / (FLUX_DIT_HEAD_DIM as f32).sqrt();
    // Parallelize over attention heads. Each head writes a disjoint column band
    // out[ti*HIDDEN + ho .. ho+HEAD_DIM] for every ti — distinct heads never
    // touch the same `out` index, so writing through a shared raw pointer is
    // data-race-free. The per-element work (score dot, softmax, weighted-sum
    // accumulation order) is byte-for-byte identical to the serial loop; only
    // the head iteration is distributed across threads => bit-identical output.
    let out_ptr = out.as_mut_ptr() as usize;
    (0..FLUX_DIT_HEADS).into_par_iter().for_each(|head| {
        let ho = head * FLUX_DIT_HEAD_DIM;
        let mut scores = vec![0.0f32; tokens];
        for ti in 0..tokens {
            let qs = ti * FLUX_DIT_HIDDEN + ho;
            let qh = &q[qs..qs + FLUX_DIT_HEAD_DIM];
            for tj in 0..tokens {
                let ks = tj * FLUX_DIT_HIDDEN + ho;
                scores[tj] = dot_product(qh, &k[ks..ks + FLUX_DIT_HEAD_DIM]) * scale;
            }
            softmax(&mut scores);
            let os = ti * FLUX_DIT_HIDDEN + ho;
            for tj in 0..tokens {
                let w = scores[tj];
                let vs = tj * FLUX_DIT_HIDDEN + ho;
                for d in 0..FLUX_DIT_HEAD_DIM {
                    // SAFETY: os+d lies in head `head`'s exclusive column band;
                    // no other rayon task writes this index.
                    unsafe {
                        let p = (out_ptr as *mut f32).add(os + d);
                        *p += w * v[vs + d];
                    }
                }
            }
        }
    });
    if out.iter().any(|x| !x.is_finite()) {
        return Err("joint attention produced non-finite output".to_string());
    }
    Ok(out)
}

// ─────────────────────────── conditioning embedder ───────────────────────────

/// Sinusoidal timestep embedding (diffusers `get_timestep_embedding`,
/// dim=256, max_period=10000, scale=1, cos-first then sin), no flip.
fn timestep_embedding(t: f32, dim: usize) -> Vec<f32> {
    let half = dim / 2;
    let mut emb = vec![0.0f32; dim];
    for i in 0..half {
        let freq = (-(10_000f32.ln()) * (i as f32) / (half as f32)).exp();
        let arg = t * freq;
        emb[i] = arg.cos();
        emb[half + i] = arg.sin();
    }
    emb
}

/// Conditioning embedder. Two 2-layer MLPs (diffusers `time_text_embed`):
///   time_emb = time_out(silu(time_in(sinusoid(t))))
///   text_emb = vec_out(silu(vec_in(pooled)))
///   vec      = time_emb + text_emb
/// Returns the 3072-dim conditioning consumed by every block's AdaLN modulation.
pub struct CondEmbedder {
    time_in: Linear,
    time_out: Linear,
    vec_in: Linear,
    vec_out: Linear,
}

impl CondEmbedder {
    pub fn load(knot_source: &str, knot: &KnotWeights) -> Result<Self, String> {
        Ok(Self {
            time_in: Linear::load(
                knot_source,
                knot,
                "flux_time_in_proj_weight",
                "flux_time_in_proj_bias",
                FLUX_DIT_HIDDEN,
                FLUX_TIME_EMB_DIM,
            )?,
            time_out: Linear::load(
                knot_source,
                knot,
                "flux_time_out_proj_weight",
                "flux_time_out_proj_bias",
                FLUX_DIT_HIDDEN,
                FLUX_DIT_HIDDEN,
            )?,
            vec_in: Linear::load(
                knot_source,
                knot,
                "flux_vec_in_proj_weight",
                "flux_vec_in_proj_bias",
                FLUX_DIT_HIDDEN,
                FLUX_POOL_DIM,
            )?,
            vec_out: Linear::load(
                knot_source,
                knot,
                "flux_vec_out_proj_weight",
                "flux_vec_out_proj_bias",
                FLUX_DIT_HIDDEN,
                FLUX_DIT_HIDDEN,
            )?,
        })
    }

    /// `t` is the continuous timestep in [0,1] (diffusers scales it by 1000).
    pub fn cond(&self, t: f32, pooled: &[f32]) -> Vec<f32> {
        let temb = timestep_embedding(t * 1000.0, FLUX_TIME_EMB_DIM);
        let mut a = self.time_in.apply(&temb);
        silu_inplace(&mut a);
        let a = self.time_out.apply(&a);
        let mut b = self.vec_in.apply(pooled);
        silu_inplace(&mut b);
        let b = self.vec_out.apply(&b);
        a.iter().zip(b.iter()).map(|(x, y)| x + y).collect()
    }
}

// ─────────────────────────── double-stream block ───────────────────────────

struct DoubleBlock {
    img_mod: Linear, // 18432 x 3072 -> 6 chunks
    txt_mod: Linear,
    img_q: Linear,
    img_k: Linear,
    img_v: Linear,
    img_q_norm: Vec<f32>,
    img_k_norm: Vec<f32>,
    img_out: Linear,
    img_fc1: Linear,
    img_fc2: Linear,
    txt_q: Linear,
    txt_k: Linear,
    txt_v: Linear,
    txt_q_norm: Vec<f32>,
    txt_k_norm: Vec<f32>,
    txt_out: Linear,
    txt_fc1: Linear,
    txt_fc2: Linear,
}

struct ModChunks {
    shift_msa: Vec<f32>,
    scale_msa: Vec<f32>,
    gate_msa: Vec<f32>,
    shift_mlp: Vec<f32>,
    scale_mlp: Vec<f32>,
    gate_mlp: Vec<f32>,
}

fn split6(m: &[f32]) -> ModChunks {
    let h = FLUX_DIT_HIDDEN;
    ModChunks {
        shift_msa: m[0..h].to_vec(),
        scale_msa: m[h..2 * h].to_vec(),
        gate_msa: m[2 * h..3 * h].to_vec(),
        shift_mlp: m[3 * h..4 * h].to_vec(),
        scale_mlp: m[4 * h..5 * h].to_vec(),
        gate_mlp: m[5 * h..6 * h].to_vec(),
    }
}

/// y = x_norm * (1 + scale) + shift (modulate)
fn modulate(x: &[f32], scale: &[f32], shift: &[f32]) -> Vec<f32> {
    let mut y = x.to_vec();
    layernorm_no_affine(&mut y);
    for ((v, s), sh) in y.iter_mut().zip(scale.iter()).zip(shift.iter()) {
        *v = *v * (1.0 + *s) + *sh;
    }
    y
}

impl DoubleBlock {
    fn load(knot_source: &str, knot: &KnotWeights, i: usize) -> Result<Self, String> {
        let p = format!("flux_dbl_{i}");
        let h = FLUX_DIT_HIDDEN;
        let lin = |wn: String, bn: String, r: usize, c: usize| -> Result<Linear, String> {
            Linear::load(knot_source, knot, &wn, &bn, r, c)
        };
        // Tag block-0 img_fc1 (12288×3072) as the per-tile speculative-dequant
        // target — the heavy DiT linear the lattice win was measured on.
        let mut img_fc1 = lin(
            format!("{p}_img_fc1_weight"),
            format!("{p}_img_fc1_bias"),
            FLUX_DIT_MLP,
            h,
        )?;
        if i == 0 {
            img_fc1.spec_target = true;
        }
        Ok(Self {
            img_mod: lin(format!("{p}_img_mod_weight"), format!("{p}_img_mod_bias"), 6 * h, h)?,
            txt_mod: lin(format!("{p}_txt_mod_weight"), format!("{p}_txt_mod_bias"), 6 * h, h)?,
            img_q: lin(format!("{p}_img_q_weight"), format!("{p}_img_q_bias"), h, h)?,
            img_k: lin(format!("{p}_img_k_weight"), format!("{p}_img_k_bias"), h, h)?,
            img_v: lin(format!("{p}_img_v_weight"), format!("{p}_img_v_bias"), h, h)?,
            img_q_norm: fetch_f32(knot_source, knot, &format!("{p}_img_q_norm_weight"))?,
            img_k_norm: fetch_f32(knot_source, knot, &format!("{p}_img_k_norm_weight"))?,
            img_out: lin(format!("{p}_img_out_weight"), format!("{p}_img_out_bias"), h, h)?,
            img_fc1,
            img_fc2: lin(format!("{p}_img_fc2_weight"), format!("{p}_img_fc2_bias"), h, FLUX_DIT_MLP)?,
            txt_q: lin(format!("{p}_txt_q_weight"), format!("{p}_txt_q_bias"), h, h)?,
            txt_k: lin(format!("{p}_txt_k_weight"), format!("{p}_txt_k_bias"), h, h)?,
            txt_v: lin(format!("{p}_txt_v_weight"), format!("{p}_txt_v_bias"), h, h)?,
            txt_q_norm: fetch_f32(knot_source, knot, &format!("{p}_txt_q_norm_weight"))?,
            txt_k_norm: fetch_f32(knot_source, knot, &format!("{p}_txt_k_norm_weight"))?,
            txt_out: lin(format!("{p}_txt_out_weight"), format!("{p}_txt_out_bias"), h, h)?,
            txt_fc1: lin(format!("{p}_txt_fc1_weight"), format!("{p}_txt_fc1_bias"), FLUX_DIT_MLP, h)?,
            txt_fc2: lin(format!("{p}_txt_fc2_weight"), format!("{p}_txt_fc2_bias"), h, FLUX_DIT_MLP)?,
        })
    }

    /// Forward over the joined stream. `img` is [img_len*h], `txt` is [txt_len*h].
    /// Updates both streams in place (residual).
    #[allow(clippy::too_many_arguments)]
    fn forward(
        &self,
        img: &mut [f32],
        txt: &mut [f32],
        cond: &[f32],
        rope: &RopeTable,
        img_len: usize,
        txt_len: usize,
    ) -> Result<(), String> {
        let h = FLUX_DIT_HIDDEN;
        let mut sc = cond.to_vec();
        silu_inplace(&mut sc);
        let img_m = split6(&self.img_mod.apply(&sc));
        let txt_m = split6(&self.txt_mod.apply(&sc));

        let tokens = txt_len + img_len; // text first

        // ── modulated norm inputs for attention (batched) ──
        let mut attn_in = vec![0.0f32; tokens * h];
        for t in 0..txt_len {
            let xm = modulate(&txt[t * h..t * h + h], &txt_m.scale_msa, &txt_m.shift_msa);
            attn_in[t * h..t * h + h].copy_from_slice(&xm);
        }
        for t in 0..img_len {
            let xm = modulate(&img[t * h..t * h + h], &img_m.scale_msa, &img_m.shift_msa);
            attn_in[(txt_len + t) * h..(txt_len + t + 1) * h].copy_from_slice(&xm);
        }
        // batched q/k/v over each stream separately (different weights)
        let txt_in_slice = &attn_in[..txt_len * h];
        let img_in_slice = &attn_in[txt_len * h..];
        let mut q = vec![0.0f32; tokens * h];
        let mut k = vec![0.0f32; tokens * h];
        let mut v = vec![0.0f32; tokens * h];
        {
            let tq = self.txt_q.apply_batch(txt_in_slice, txt_len);
            let tk = self.txt_k.apply_batch(txt_in_slice, txt_len);
            let tv = self.txt_v.apply_batch(txt_in_slice, txt_len);
            q[..txt_len * h].copy_from_slice(&tq);
            k[..txt_len * h].copy_from_slice(&tk);
            v[..txt_len * h].copy_from_slice(&tv);
            let iq = self.img_q.apply_batch(img_in_slice, img_len);
            let ik = self.img_k.apply_batch(img_in_slice, img_len);
            let iv = self.img_v.apply_batch(img_in_slice, img_len);
            q[txt_len * h..].copy_from_slice(&iq);
            k[txt_len * h..].copy_from_slice(&ik);
            v[txt_len * h..].copy_from_slice(&iv);
        }
        // per-head qk norm + rope per token
        for t in 0..txt_len {
            norm_heads(&mut q[t * h..t * h + h], &self.txt_q_norm);
            norm_heads(&mut k[t * h..t * h + h], &self.txt_k_norm);
            rope.apply_token(&mut q[t * h..t * h + h], t);
            rope.apply_token(&mut k[t * h..t * h + h], t);
        }
        for t in 0..img_len {
            let tok = txt_len + t;
            norm_heads(&mut q[tok * h..tok * h + h], &self.img_q_norm);
            norm_heads(&mut k[tok * h..tok * h + h], &self.img_k_norm);
            rope.apply_token(&mut q[tok * h..tok * h + h], tok);
            rope.apply_token(&mut k[tok * h..tok * h + h], tok);
        }

        let attn = joint_attention(&q, &k, &v, tokens)?;

        // ── attention out (batched per stream) + gated residual ──
        let txt_proj = self.txt_out.apply_batch(&attn[..txt_len * h], txt_len);
        let img_proj = self.img_out.apply_batch(&attn[txt_len * h..], img_len);
        for t in 0..txt_len {
            for d in 0..h {
                txt[t * h + d] += txt_m.gate_msa[d] * txt_proj[t * h + d];
            }
        }
        for t in 0..img_len {
            for d in 0..h {
                img[t * h + d] += img_m.gate_msa[d] * img_proj[t * h + d];
            }
        }
        // ── MLP (batched) ──
        let mut txt_mlp_in = vec![0.0f32; txt_len * h];
        for t in 0..txt_len {
            let xm = modulate(&txt[t * h..t * h + h], &txt_m.scale_mlp, &txt_m.shift_mlp);
            txt_mlp_in[t * h..t * h + h].copy_from_slice(&xm);
        }
        let mut txt_hid = self.txt_fc1.apply_batch(&txt_mlp_in, txt_len);
        gelu_inplace(&mut txt_hid);
        let txt_out = self.txt_fc2.apply_batch(&txt_hid, txt_len);
        for t in 0..txt_len {
            for d in 0..h {
                txt[t * h + d] += txt_m.gate_mlp[d] * txt_out[t * h + d];
            }
        }
        let mut img_mlp_in = vec![0.0f32; img_len * h];
        for t in 0..img_len {
            let xm = modulate(&img[t * h..t * h + h], &img_m.scale_mlp, &img_m.shift_mlp);
            img_mlp_in[t * h..t * h + h].copy_from_slice(&xm);
        }
        let mut img_hid = self.img_fc1.apply_batch(&img_mlp_in, img_len);
        gelu_inplace(&mut img_hid);
        let img_out = self.img_fc2.apply_batch(&img_hid, img_len);
        for t in 0..img_len {
            for d in 0..h {
                img[t * h + d] += img_m.gate_mlp[d] * img_out[t * h + d];
            }
        }
        if img.iter().chain(txt.iter()).any(|x| !x.is_finite()) {
            return Err("double block produced non-finite stream".to_string());
        }
        Ok(())
    }
}

/// DEBUG: deterministic block-0 (double-block 0) forward for numeric cross-check
/// against a diffusers `FluxTransformerBlock`. Builds a fixed pseudo-random
/// img/txt/cond input (matching the python reference seeding), runs double-block
/// 0, and returns (img_out, txt_out, plus staged intermediates for divergence
/// localization). Not used in production paths.
#[allow(clippy::type_complexity)]
pub fn debug_block0_forward(
    knot_source: &str,
    knot: &KnotWeights,
    txt_len: usize,
    latent_h: usize,
    latent_w: usize,
) -> Result<DebugBlock0Output, String> {
    let h = FLUX_DIT_HIDDEN;
    let img_len = latent_h * latent_w;
    // Deterministic inputs: x[i] = sin(i*0.1 + offset)*0.5 style, matched in python.
    let det = |seed: usize, n: usize| -> Vec<f32> {
        let mut v = vec![0.0f32; n];
        for i in 0..n {
            let a = ((i + 1) as f32) * 0.0007 + (seed as f32) * 0.013;
            v[i] = (a.sin() * 0.8 + (a * 2.3).cos() * 0.2) * 0.5;
        }
        v
    };
    let mut img = det(1, img_len * h);
    let mut txt = det(2, txt_len * h);
    let cond = det(3, h);

    let img_in0 = img.clone();
    let txt_in0 = txt.clone();

    let block = DoubleBlock::load(knot_source, knot, 0)?;
    let rope = RopeTable::build(txt_len, latent_h, latent_w);

    // Capture staged intermediates by re-running the block math inline (mirrors
    // DoubleBlock::forward) so we can diff stage-by-stage with the reference.
    let mut sc = cond.to_vec();
    silu_inplace(&mut sc);
    let img_m = split6(&block.img_mod.apply(&sc));
    let txt_m = split6(&block.txt_mod.apply(&sc));
    let tokens = txt_len + img_len;

    let mut attn_in = vec![0.0f32; tokens * h];
    for t in 0..txt_len {
        let xm = modulate(&txt[t * h..t * h + h], &txt_m.scale_msa, &txt_m.shift_msa);
        attn_in[t * h..t * h + h].copy_from_slice(&xm);
    }
    for t in 0..img_len {
        let xm = modulate(&img[t * h..t * h + h], &img_m.scale_msa, &img_m.shift_msa);
        attn_in[(txt_len + t) * h..(txt_len + t + 1) * h].copy_from_slice(&xm);
    }
    let modulated_attn_in = attn_in.clone();

    let txt_in_slice = &attn_in[..txt_len * h];
    let img_in_slice = &attn_in[txt_len * h..];
    let mut q = vec![0.0f32; tokens * h];
    let mut k = vec![0.0f32; tokens * h];
    let mut v = vec![0.0f32; tokens * h];
    {
        let tq = block.txt_q.apply_batch(txt_in_slice, txt_len);
        let tk = block.txt_k.apply_batch(txt_in_slice, txt_len);
        let tv = block.txt_v.apply_batch(txt_in_slice, txt_len);
        q[..txt_len * h].copy_from_slice(&tq);
        k[..txt_len * h].copy_from_slice(&tk);
        v[..txt_len * h].copy_from_slice(&tv);
        let iq = block.img_q.apply_batch(img_in_slice, img_len);
        let ik = block.img_k.apply_batch(img_in_slice, img_len);
        let iv = block.img_v.apply_batch(img_in_slice, img_len);
        q[txt_len * h..].copy_from_slice(&iq);
        k[txt_len * h..].copy_from_slice(&ik);
        v[txt_len * h..].copy_from_slice(&iv);
    }
    let qkv_pre_norm = (q.clone(), k.clone(), v.clone());
    for t in 0..txt_len {
        norm_heads(&mut q[t * h..t * h + h], &block.txt_q_norm);
        norm_heads(&mut k[t * h..t * h + h], &block.txt_k_norm);
        rope.apply_token(&mut q[t * h..t * h + h], t);
        rope.apply_token(&mut k[t * h..t * h + h], t);
    }
    for t in 0..img_len {
        let tok = txt_len + t;
        norm_heads(&mut q[tok * h..tok * h + h], &block.img_q_norm);
        norm_heads(&mut k[tok * h..tok * h + h], &block.img_k_norm);
        rope.apply_token(&mut q[tok * h..tok * h + h], tok);
        rope.apply_token(&mut k[tok * h..tok * h + h], tok);
    }
    let qk_post_rope = (q.clone(), k.clone());
    let attn = joint_attention(&q, &k, &v, tokens)?;
    let attn_out = attn.clone();

    // Now run the real forward for the final residual outputs.
    block.forward(&mut img, &mut txt, &cond, &rope, img_len, txt_len)?;

    Ok(DebugBlock0Output {
        h,
        txt_len,
        img_len,
        cond_silu: sc,
        img_mod: flatten_mod(&img_m),
        txt_mod: flatten_mod(&txt_m),
        img_in0,
        txt_in0,
        modulated_attn_in,
        q_pre_norm: qkv_pre_norm.0,
        k_pre_norm: qkv_pre_norm.1,
        v_proj: qkv_pre_norm.2,
        q_post_rope: qk_post_rope.0,
        k_post_rope: qk_post_rope.1,
        attn_out,
        img_out: img,
        txt_out: txt,
    })
}

/// DEBUG: isolated final AdaLN-out + final_layer forward on a fixed input, with
/// a selectable scale/shift ordering, for numeric cross-check.
/// img_out = det(7) over [img_len*h]; cond = det(3) over [h].
/// `scale_first`: if true use current production order (m[0..h]=scale,
/// m[h..2h]=shift); if false use swapped order (m[0..h]=shift, m[h..2h]=scale).
pub fn debug_final_forward(
    knot_source: &str,
    knot: &KnotWeights,
    img_len: usize,
    scale_first: bool,
) -> Result<Vec<f32>, String> {
    let h = FLUX_DIT_HIDDEN;
    let det = |seed: usize, n: usize| -> Vec<f32> {
        let mut v = vec![0.0f32; n];
        for i in 0..n {
            let a = ((i + 1) as f32) * 0.0007 + (seed as f32) * 0.013;
            v[i] = (a.sin() * 0.8 + (a * 2.3).cos() * 0.2) * 0.5;
        }
        v
    };
    let img_out = det(7, img_len * h);
    let cond = det(3, h);

    let final_adaln = Linear::load(
        knot_source,
        knot,
        "flux_final_adaln_weight",
        "flux_final_adaln_bias",
        2 * h,
        h,
    )?;
    let final_layer = Linear::load(
        knot_source,
        knot,
        "flux_final_layer_weight",
        "flux_final_layer_bias",
        FLUX_IN_CHANNELS,
        h,
    )?;
    let mut sc = cond.clone();
    silu_inplace(&mut sc);
    let m = final_adaln.apply(&sc);
    let (scale, shift) = if scale_first {
        (&m[0..h], &m[h..2 * h])
    } else {
        (&m[h..2 * h], &m[0..h])
    };
    let mut final_in = vec![0.0f32; img_len * h];
    for i in 0..img_len {
        let xm = modulate(&img_out[i * h..(i + 1) * h], scale, shift);
        final_in[i * h..(i + 1) * h].copy_from_slice(&xm);
    }
    Ok(final_layer.apply_batch(&final_in, img_len))
}

/// DEBUG: isolated single-stream block 0 forward on a fixed deterministic input,
/// for numeric cross-check against a diffusers `FluxSingleTransformerBlock`.
/// The joined stream is [txt_len ++ img_len] tokens (text first), matching the
/// production `velocity` concat order. Captures staged intermediates so any
/// divergence (modulation, qkv, rope, gelu, attn, concat, out-proj+gate) can be
/// localized. Not used in production paths.
pub struct DebugSingleBlock0Output {
    pub h: usize,
    pub txt_len: usize,
    pub img_len: usize,
    pub stream_in: Vec<f32>,
    pub cond_silu: Vec<f32>,
    pub modulation: Vec<f32>, // [shift|scale|gate], 3*h
    pub modulated_in: Vec<f32>,
    pub q_pre_norm: Vec<f32>,
    pub k_pre_norm: Vec<f32>,
    pub v_proj: Vec<f32>,
    pub mlp_hidden_gelu: Vec<f32>,
    pub q_post_rope: Vec<f32>,
    pub k_post_rope: Vec<f32>,
    pub attn_out: Vec<f32>,
    pub stream_out: Vec<f32>,
}

pub fn debug_single_block0_forward(
    knot_source: &str,
    knot: &KnotWeights,
    txt_len: usize,
    latent_h: usize,
    latent_w: usize,
) -> Result<DebugSingleBlock0Output, String> {
    let h = FLUX_DIT_HIDDEN;
    let img_len = latent_h * latent_w;
    let tokens = txt_len + img_len;
    let det = |seed: usize, n: usize| -> Vec<f32> {
        let mut v = vec![0.0f32; n];
        for i in 0..n {
            let a = ((i + 1) as f32) * 0.0007 + (seed as f32) * 0.013;
            v[i] = (a.sin() * 0.8 + (a * 2.3).cos() * 0.2) * 0.5;
        }
        v
    };
    // joined stream: text tokens (seed 2) then image tokens (seed 1), to mirror
    // the production concat (txt first). cond uses seed 3.
    let mut stream = vec![0.0f32; tokens * h];
    let txt_part = det(2, txt_len * h);
    let img_part = det(1, img_len * h);
    stream[..txt_len * h].copy_from_slice(&txt_part);
    stream[txt_len * h..].copy_from_slice(&img_part);
    let cond = det(3, h);
    let stream_in = stream.clone();

    let block = SingleBlock::load(knot_source, knot, 0)?;
    let rope = RopeTable::build(txt_len, latent_h, latent_w);

    // Re-run the block math inline (mirrors SingleBlock::forward) to capture
    // intermediates, then call the real forward for the final stream output.
    let mut sc = cond.clone();
    silu_inplace(&mut sc);
    let m = block.mod_lin.apply(&sc);
    let shift = &m[0..h];
    let scale = &m[h..2 * h];
    let modulation = m.clone();

    let mut xin = vec![0.0f32; tokens * h];
    for t in 0..tokens {
        let xm = modulate(&stream[t * h..t * h + h], scale, shift);
        xin[t * h..t * h + h].copy_from_slice(&xm);
    }
    let modulated_in = xin.clone();
    let mut q = block.q.apply_batch(&xin, tokens);
    let mut k = block.k.apply_batch(&xin, tokens);
    let vv = block.v.apply_batch(&xin, tokens);
    let mut mlp_hidden = block.mlp.apply_batch(&xin, tokens);
    gelu_inplace(&mut mlp_hidden);
    let (q_pre_norm, k_pre_norm) = (q.clone(), k.clone());
    for t in 0..tokens {
        norm_heads(&mut q[t * h..t * h + h], &block.q_norm);
        norm_heads(&mut k[t * h..t * h + h], &block.k_norm);
        rope.apply_token(&mut q[t * h..t * h + h], t);
        rope.apply_token(&mut k[t * h..t * h + h], t);
    }
    let (q_post_rope, k_post_rope) = (q.clone(), k.clone());
    let attn = joint_attention(&q, &k, &vv, tokens)?;

    block.forward(&mut stream, &cond, &rope, tokens)?;

    Ok(DebugSingleBlock0Output {
        h,
        txt_len,
        img_len,
        stream_in,
        cond_silu: sc,
        modulation,
        modulated_in,
        q_pre_norm,
        k_pre_norm,
        v_proj: vv,
        mlp_hidden_gelu: mlp_hidden,
        q_post_rope,
        k_post_rope,
        attn_out: attn,
        stream_out: stream,
    })
}

fn flatten_mod(m: &ModChunks) -> Vec<f32> {
    let mut out = Vec::new();
    out.extend_from_slice(&m.shift_msa);
    out.extend_from_slice(&m.scale_msa);
    out.extend_from_slice(&m.gate_msa);
    out.extend_from_slice(&m.shift_mlp);
    out.extend_from_slice(&m.scale_mlp);
    out.extend_from_slice(&m.gate_mlp);
    out
}

pub struct DebugBlock0Output {
    pub h: usize,
    pub txt_len: usize,
    pub img_len: usize,
    pub cond_silu: Vec<f32>,
    pub img_mod: Vec<f32>,
    pub txt_mod: Vec<f32>,
    pub img_in0: Vec<f32>,
    pub txt_in0: Vec<f32>,
    pub modulated_attn_in: Vec<f32>,
    pub q_pre_norm: Vec<f32>,
    pub k_pre_norm: Vec<f32>,
    pub v_proj: Vec<f32>,
    pub q_post_rope: Vec<f32>,
    pub k_post_rope: Vec<f32>,
    pub attn_out: Vec<f32>,
    pub img_out: Vec<f32>,
    pub txt_out: Vec<f32>,
}

/// Apply per-head RMS norm to a full hidden vector (heads * head_dim).
fn norm_heads(hidden: &mut [f32], scale: &[f32]) {
    for head in 0..FLUX_DIT_HEADS {
        let o = head * FLUX_DIT_HEAD_DIM;
        rms_norm_head(&mut hidden[o..o + FLUX_DIT_HEAD_DIM], scale);
    }
}

// ─────────────────────────── single-stream block ───────────────────────────

struct SingleBlock {
    mod_lin: Linear, // 9216 x 3072 -> 3 chunks
    q: Linear,
    k: Linear,
    v: Linear,
    q_norm: Vec<f32>,
    k_norm: Vec<f32>,
    mlp: Linear,  // 12288 x 3072 (MLP in)
    out: Linear,  // 3072 x 15360 (attn 3072 ++ mlp 12288)
}

impl SingleBlock {
    fn load(knot_source: &str, knot: &KnotWeights, i: usize) -> Result<Self, String> {
        let p = format!("flux_sgl_{i}");
        let h = FLUX_DIT_HIDDEN;
        let lin = |wn: String, bn: String, r: usize, c: usize| -> Result<Linear, String> {
            Linear::load(knot_source, knot, &wn, &bn, r, c)
        };
        Ok(Self {
            mod_lin: lin(format!("{p}_mod_weight"), format!("{p}_mod_bias"), 3 * h, h)?,
            q: lin(format!("{p}_q_weight"), format!("{p}_q_bias"), h, h)?,
            k: lin(format!("{p}_k_weight"), format!("{p}_k_bias"), h, h)?,
            v: lin(format!("{p}_v_weight"), format!("{p}_v_bias"), h, h)?,
            q_norm: fetch_f32(knot_source, knot, &format!("{p}_q_norm_weight"))?,
            k_norm: fetch_f32(knot_source, knot, &format!("{p}_k_norm_weight"))?,
            mlp: lin(format!("{p}_mlp_weight"), format!("{p}_mlp_bias"), FLUX_DIT_MLP, h)?,
            out: lin(
                format!("{p}_out_weight"),
                format!("{p}_out_bias"),
                h,
                h + FLUX_DIT_MLP,
            )?,
        })
    }

    /// joined `stream` is [tokens * h] (text first then image).
    fn forward(&self, stream: &mut [f32], cond: &[f32], rope: &RopeTable, tokens: usize) -> Result<(), String> {
        let h = FLUX_DIT_HIDDEN;
        let mut sc = cond.to_vec();
        silu_inplace(&mut sc);
        let m = self.mod_lin.apply(&sc);
        let shift = &m[0..h];
        let scale = &m[h..2 * h];
        let gate = &m[2 * h..3 * h];

        // modulated norm input (batched)
        let mut xin = vec![0.0f32; tokens * h];
        for t in 0..tokens {
            let xm = modulate(&stream[t * h..t * h + h], scale, shift);
            xin[t * h..t * h + h].copy_from_slice(&xm);
        }
        let mut q = self.q.apply_batch(&xin, tokens);
        let mut k = self.k.apply_batch(&xin, tokens);
        let vv = self.v.apply_batch(&xin, tokens);
        let mut mlp_hidden = self.mlp.apply_batch(&xin, tokens);
        gelu_inplace(&mut mlp_hidden);
        for t in 0..tokens {
            norm_heads(&mut q[t * h..t * h + h], &self.q_norm);
            norm_heads(&mut k[t * h..t * h + h], &self.k_norm);
            rope.apply_token(&mut q[t * h..t * h + h], t);
            rope.apply_token(&mut k[t * h..t * h + h], t);
        }

        let attn = joint_attention(&q, &k, &vv, tokens)?;

        // out projection over concatenated [attn ++ mlp_hidden] (batched)
        let catdim = h + FLUX_DIT_MLP;
        let mut cat = vec![0.0f32; tokens * catdim];
        for t in 0..tokens {
            cat[t * catdim..t * catdim + h].copy_from_slice(&attn[t * h..t * h + h]);
            cat[t * catdim + h..(t + 1) * catdim]
                .copy_from_slice(&mlp_hidden[t * FLUX_DIT_MLP..(t + 1) * FLUX_DIT_MLP]);
        }
        let proj = self.out.apply_batch(&cat, tokens);
        for t in 0..tokens {
            for d in 0..h {
                stream[t * h + d] += gate[d] * proj[t * h + d];
            }
        }
        if stream.iter().any(|x| !x.is_finite()) {
            return Err("single block produced non-finite stream".to_string());
        }
        Ok(())
    }
}

// ─────────────────────────── full DiT ───────────────────────────

pub struct FluxDit {
    cond: CondEmbedder,
    img_in: Linear,  // 3072 x 64
    txt_in: Linear,  // 3072 x 4096
    double: Vec<DoubleBlock>,
    single: Vec<SingleBlock>,
    final_adaln: Linear, // 6144 x 3072 -> shift,scale
    final_layer: Linear, // 64 x 3072
}

impl FluxDit {
    pub fn load(knot_source: &str, knot: &KnotWeights) -> Result<Self, String> {
        let cond = CondEmbedder::load(knot_source, knot)?;
        let img_in = Linear::load(
            knot_source,
            knot,
            "flux_img_in_weight",
            "flux_img_in_bias",
            FLUX_DIT_HIDDEN,
            FLUX_IN_CHANNELS,
        )?;
        let txt_in = Linear::load(
            knot_source,
            knot,
            "flux_txt_in_weight",
            "flux_txt_in_bias",
            FLUX_DIT_HIDDEN,
            FLUX_TXT_DIM,
        )?;
        let mut double = Vec::with_capacity(FLUX_NUM_DOUBLE);
        for i in 0..FLUX_NUM_DOUBLE {
            double.push(DoubleBlock::load(knot_source, knot, i)?);
        }
        let mut single = Vec::with_capacity(FLUX_NUM_SINGLE);
        for i in 0..FLUX_NUM_SINGLE {
            single.push(SingleBlock::load(knot_source, knot, i)?);
        }
        let final_adaln = Linear::load(
            knot_source,
            knot,
            "flux_final_adaln_weight",
            "flux_final_adaln_bias",
            2 * FLUX_DIT_HIDDEN,
            FLUX_DIT_HIDDEN,
        )?;
        let final_layer = Linear::load(
            knot_source,
            knot,
            "flux_final_layer_weight",
            "flux_final_layer_bias",
            FLUX_IN_CHANNELS,
            FLUX_DIT_HIDDEN,
        )?;
        Ok(Self {
            cond,
            img_in,
            txt_in,
            double,
            single,
            final_adaln,
            final_layer,
        })
    }

    /// Predict velocity in patch-token space.
    /// `img_tokens`: [img_len * 64] patchified latents.
    /// `txt`: [txt_len * 4096] T5 hidden states.
    /// `pooled`: [768] CLIP pooled.
    /// Returns [img_len * 64] velocity tokens.
    pub fn velocity(
        &self,
        img_tokens: &[f32],
        txt: &[f32],
        pooled: &[f32],
        t: f32,
        latent_h: usize,
        latent_w: usize,
    ) -> Result<Vec<f32>, String> {
        let h = FLUX_DIT_HIDDEN;
        let img_len = latent_h * latent_w;
        let txt_len = txt.len() / FLUX_TXT_DIM;
        if img_tokens.len() != img_len * FLUX_IN_CHANNELS {
            return Err(format!(
                "img token length mismatch: expected {}, got {}",
                img_len * FLUX_IN_CHANNELS,
                img_tokens.len()
            ));
        }

        // Trace the FIRST velocity pass marker-by-marker (only once) so a silent
        // hang/OOM in the DiT forward entry is pinpointed. Subsequent passes are
        // silent (the hot loop).
        let trace = {
            static FIRST: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(true);
            FIRST.swap(false, std::sync::atomic::Ordering::Relaxed)
        };
        if trace {
            dit_marker(&format!(
                "velocity entry: img_len={img_len} txt_len={txt_len} hidden={h}"
            ));
        }

        let cond = self.cond.cond(t, pooled);
        if trace {
            dit_marker("after cond");
        }
        let rope = RopeTable::build(txt_len, latent_h, latent_w);
        if trace {
            dit_marker(&format!("after RopeTable::build (tokens={})", rope.tokens));
        }

        // project streams into hidden space (batched)
        let mut img = self.img_in.apply_batch(img_tokens, img_len);
        if trace {
            dit_marker("after img_in.apply_batch");
        }
        let mut txt_h = self.txt_in.apply_batch(txt, txt_len);
        if trace {
            dit_marker("after txt_in.apply_batch");
        }

        for (bi, block) in self.double.iter().enumerate() {
            if trace {
                dit_marker(&format!("before double block {bi}.forward"));
            }
            block
                .forward(&mut img, &mut txt_h, &cond, &rope, img_len, txt_len)
                .map_err(|e| format!("double block {bi}: {e}"))?;
        }
        if trace {
            dit_marker("after all double blocks");
        }

        // concat text++image for single stream
        let tokens = txt_len + img_len;
        let mut stream = vec![0.0f32; tokens * h];
        stream[..txt_len * h].copy_from_slice(&txt_h);
        stream[txt_len * h..].copy_from_slice(&img);
        if trace {
            dit_marker(&format!("single-stream concat done (tokens={tokens})"));
        }
        for (bi, block) in self.single.iter().enumerate() {
            if trace && bi == 0 {
                dit_marker("before single block 0.forward");
            }
            block
                .forward(&mut stream, &cond, &rope, tokens)
                .map_err(|e| format!("single block {bi}: {e}"))?;
        }
        if trace {
            dit_marker("after all single blocks");
        }
        // take image part back
        let img_out = &stream[txt_len * h..];

        // final AdaLN-out: scale/shift from silu(cond), then final linear to 64.
        // diffusers AdaLayerNormContinuous: `scale, shift = chunk(linear(silu(cond)))`
        // then `norm(x)*(1+scale)+shift` -- i.e. SCALE is the first half. The diffusers
        // encode path (encode-knot.py) stores `norm_out.linear` VERBATIM into
        // flux_final_adaln, and this production knot is diffusers-dialect, so the rows
        // are [scale, shift]: scale=m[0..h], shift=m[h..2h]. (The previous code read
        // these swapped -- the FLUX noise bug; the old cos=1.0 "verification" was
        // self-referential against a reference that shared the same swap. Confirmed
        // against the diffusers normalization.py source, 2026-06-17.)
        let mut sc = cond.clone();
        silu_inplace(&mut sc);
        let m = self.final_adaln.apply(&sc);
        let scale = &m[0..h];
        let shift = &m[h..2 * h];
        let mut final_in = vec![0.0f32; img_len * h];
        for i in 0..img_len {
            let xm = modulate(&img_out[i * h..(i + 1) * h], scale, shift);
            final_in[i * h..(i + 1) * h].copy_from_slice(&xm);
        }
        let velocity = self.final_layer.apply_batch(&final_in, img_len);
        if velocity.iter().any(|x| !x.is_finite()) {
            return Err("final velocity is non-finite".to_string());
        }
        Ok(velocity)
    }
}

// ─────────────────────────── flow-match scheduler ───────────────────────────

/// schnell sigma schedule. Linear sigmas in [1,0] over `steps`, with the FLUX
/// time-shift (mu derived from image sequence length). Returns `steps+1` sigmas.
pub fn flux_schnell_sigmas(steps: usize, image_seq_len: usize) -> Vec<f32> {
    // base linear sigmas from 1.0 down to ~0
    let mut sigmas: Vec<f32> = (0..=steps)
        .map(|i| 1.0 - i as f32 / steps as f32)
        .collect();
    // dynamic shift mu = m * seq + b  (diffusers FlowMatchEulerDiscrete defaults
    // for FLUX: base_seq=256, max_seq=4096, base_shift=0.5, max_shift=1.15).
    let (x1, x2, y1, y2) = (256.0f32, 4096.0f32, 0.5f32, 1.15f32);
    let m = (y2 - y1) / (x2 - x1);
    let b = y1 - m * x1;
    let mu = m * image_seq_len as f32 + b;
    let shift = mu.exp();
    for s in sigmas.iter_mut() {
        // time shift: sigma' = shift*sigma / (1 + (shift-1)*sigma)
        *s = shift * *s / (1.0 + (shift - 1.0) * *s);
    }
    sigmas
}

// ─────────────────────────── VAE decoder ───────────────────────────

const VAE_GROUPS: usize = 32;
const VAE_SCALING: f32 = 0.3611;
const VAE_SHIFT: f32 = 0.1159;

struct ConvW {
    w: Vec<f32>, // dequantized [out, in, k, k]
    b: Vec<f32>,
    out_c: usize,
    in_c: usize,
    k: usize,
}

fn dequant_conv(knot_source: &str, knot: &KnotWeights, wn: &str, bn: &str) -> Result<ConvW, String> {
    let t = fetch_knot_tensor_bytes_from_metadata(
        knot_source,
        &knot.metadata,
        knot.payload_offset,
        wn,
    )
    .map_err(|e| format!("fetch {wn}: {e}"))?;
    let shape = t
        .info
        .shape
        .as_ref()
        .ok_or_else(|| format!("{wn} missing shape"))?;
    if shape.len() != 4 {
        return Err(format!("{wn} expected 4D, got {shape:?}"));
    }
    let (out_c, in_c, k) = (shape[0], shape[1], shape[2]);
    let total = out_c * in_c * k * k;
    let w = if t.info.tensor_type.eq_ignore_ascii_case("Q8_0") {
        // The KNOT packs Q8_0 as a SINGLE flat stream of 32-element blocks over
        // the whole flattened tensor (34 bytes/block: f16 scale + 32 i8), with
        // NO per-row padding — blocks span row boundaries. (in_c*k*k) for small
        // convs (e.g. conv_in 16*3*3=144) is NOT a multiple of 32, so the old
        // per-row dequant mis-aligned every row after the first. Dequantize the
        // whole tensor as one contiguous block stream to match the ground truth.
        crate::math::dequantize_q8_0_flat(&t.bytes, total)
    } else {
        let mut w = vec![0.0f32; total];
        for (i, c) in t.bytes.chunks_exact(4).enumerate() {
            if i < total {
                w[i] = f32::from_le_bytes([c[0], c[1], c[2], c[3]]);
            }
        }
        w
    };
    let b = fetch_f32(knot_source, knot, bn)?;
    Ok(ConvW {
        w,
        b,
        out_c,
        in_c,
        k,
    })
}

/// NCHW conv2d, stride 1, padding (k-1)/2 (same).
fn conv2d(input: &[f32], in_c: usize, h: usize, w: usize, cw: &ConvW) -> Vec<f32> {
    use gnosis_frf::prelude::*;
    let k = cw.k;
    let pad = (k - 1) / 2;
    let plane = h * w;
    let mut out = vec![0.0f32; cw.out_c * plane];
    // Parallelize over output channels: each oc writes a disjoint `plane`-sized
    // slice and reads shared (immutable) input/weights. The per-output
    // accumulation order is byte-for-byte identical to the serial version — we
    // only changed which thread runs each oc, not the inner float add order, so
    // results are bit-identical (not merely <1e-4).
    out.par_chunks_mut(plane)
        .enumerate()
        .for_each(|(oc, out_chan)| {
            let bias = cw.b[oc];
            let wbase = oc * cw.in_c;
            for oy in 0..h {
                for ox in 0..w {
                    let mut acc = bias;
                    for ic in 0..in_c {
                        let inbase = ic * plane;
                        let wic = ((wbase + ic) * k) * k;
                        for ky in 0..k {
                            let iy = oy as isize + ky as isize - pad as isize;
                            if iy < 0 || iy >= h as isize {
                                continue;
                            }
                            let inrow = inbase + iy as usize * w;
                            let wrow = wic + ky * k;
                            for kx in 0..k {
                                let ix = ox as isize + kx as isize - pad as isize;
                                if ix < 0 || ix >= w as isize {
                                    continue;
                                }
                                let iv = input[inrow + ix as usize];
                                let wv = cw.w[wrow + kx];
                                acc += iv * wv;
                            }
                        }
                    }
                    out_chan[oy * w + ox] = acc;
                }
            }
        });
    out
}

/// GroupNorm (32 groups) + SiLU, NCHW.
fn group_norm_silu(x: &mut [f32], c: usize, h: usize, w: usize, weight: &[f32], bias: &[f32], silu_act: bool) {
    let cpg = c / VAE_GROUPS;
    let plane = h * w;
    for g in 0..VAE_GROUPS {
        let start = g * cpg;
        let n = (cpg * plane) as f32;
        let mut mean = 0.0f32;
        for ch in start..start + cpg {
            for p in 0..plane {
                mean += x[ch * plane + p];
            }
        }
        mean /= n;
        let mut var = 0.0f32;
        for ch in start..start + cpg {
            for p in 0..plane {
                let d = x[ch * plane + p] - mean;
                var += d * d;
            }
        }
        var /= n;
        let inv = 1.0 / (var + 1e-6).sqrt();
        for ch in start..start + cpg {
            let gw = weight[ch];
            let gb = bias[ch];
            for p in 0..plane {
                let idx = ch * plane + p;
                let mut val = (x[idx] - mean) * inv * gw + gb;
                if silu_act {
                    val = silu(val);
                }
                x[idx] = val;
            }
        }
    }
}

struct ResnetW {
    norm1_w: Vec<f32>,
    norm1_b: Vec<f32>,
    conv1: ConvW,
    norm2_w: Vec<f32>,
    norm2_b: Vec<f32>,
    conv2: ConvW,
    shortcut: Option<ConvW>,
}

impl ResnetW {
    fn load(knot_source: &str, knot: &KnotWeights, prefix: &str) -> Result<Self, String> {
        let shortcut = if knot
            .metadata
            .contains_key(&format!("{prefix}_conv_shortcut_weight"))
        {
            Some(dequant_conv(
                knot_source,
                knot,
                &format!("{prefix}_conv_shortcut_weight"),
                &format!("{prefix}_conv_shortcut_bias"),
            )?)
        } else {
            None
        };
        Ok(Self {
            norm1_w: fetch_f32(knot_source, knot, &format!("{prefix}_norm1_weight"))?,
            norm1_b: fetch_f32(knot_source, knot, &format!("{prefix}_norm1_bias"))?,
            conv1: dequant_conv(knot_source, knot, &format!("{prefix}_conv1_weight"), &format!("{prefix}_conv1_bias"))?,
            norm2_w: fetch_f32(knot_source, knot, &format!("{prefix}_norm2_weight"))?,
            norm2_b: fetch_f32(knot_source, knot, &format!("{prefix}_norm2_bias"))?,
            conv2: dequant_conv(knot_source, knot, &format!("{prefix}_conv2_weight"), &format!("{prefix}_conv2_bias"))?,
            shortcut,
        })
    }

    fn forward(&self, x: &[f32], c: usize, h: usize, w: usize) -> (Vec<f32>, usize) {
        let mut hcur = x.to_vec();
        group_norm_silu(&mut hcur, c, h, w, &self.norm1_w, &self.norm1_b, true);
        let mut out = conv2d(&hcur, c, h, w, &self.conv1);
        let oc = self.conv1.out_c;
        group_norm_silu(&mut out, oc, h, w, &self.norm2_w, &self.norm2_b, true);
        let out = conv2d(&out, oc, h, w, &self.conv2);
        let oc2 = self.conv2.out_c;
        // residual
        let res = match &self.shortcut {
            Some(sc) => conv2d(x, c, h, w, sc),
            None => x.to_vec(),
        };
        let mut y = vec![0.0f32; oc2 * h * w];
        for i in 0..y.len() {
            y[i] = out[i] + res[i];
        }
        (y, oc2)
    }
}

fn nearest_upsample(x: &[f32], c: usize, h: usize, w: usize) -> (Vec<f32>, usize, usize) {
    let (nh, nw) = (h * 2, w * 2);
    let mut out = vec![0.0f32; c * nh * nw];
    for ch in 0..c {
        for y in 0..nh {
            for xx in 0..nw {
                out[ch * nh * nw + y * nw + xx] = x[ch * h * w + (y / 2) * w + (xx / 2)];
            }
        }
    }
    (out, nh, nw)
}

/// Self-attention in the VAE mid block (NCHW, spatial tokens).
struct VaeAttn {
    gn_w: Vec<f32>,
    gn_b: Vec<f32>,
    q: Linear,
    k: Linear,
    v: Linear,
    o: Linear,
}

impl VaeAttn {
    fn load(knot_source: &str, knot: &KnotWeights, prefix: &str) -> Result<Self, String> {
        let lin = |n: &str| -> Result<Linear, String> {
            Linear::load(
                knot_source,
                knot,
                &format!("{prefix}_{n}_weight"),
                &format!("{prefix}_{n}_bias"),
                512,
                512,
            )
        };
        Ok(Self {
            gn_w: fetch_f32(knot_source, knot, &format!("{prefix}_group_norm_weight"))?,
            gn_b: fetch_f32(knot_source, knot, &format!("{prefix}_group_norm_bias"))?,
            q: lin("to_q")?,
            k: lin("to_k")?,
            v: lin("to_v")?,
            o: lin("to_out_0")?,
        })
    }

    fn forward(&self, x: &[f32], c: usize, h: usize, w: usize) -> Vec<f32> {
        // group norm (no silu)
        let mut hn = x.to_vec();
        group_norm_silu(&mut hn, c, h, w, &self.gn_w, &self.gn_b, false);
        let n = h * w;
        // gather per-token channel vectors
        let mut tok = vec![0.0f32; n * c];
        for p in 0..n {
            for ch in 0..c {
                tok[p * c + ch] = hn[ch * n + p];
            }
        }
        let mut q = vec![0.0f32; n * c];
        let mut k = vec![0.0f32; n * c];
        let mut v = vec![0.0f32; n * c];
        for p in 0..n {
            q[p * c..(p + 1) * c].copy_from_slice(&self.q.apply(&tok[p * c..(p + 1) * c]));
            k[p * c..(p + 1) * c].copy_from_slice(&self.k.apply(&tok[p * c..(p + 1) * c]));
            v[p * c..(p + 1) * c].copy_from_slice(&self.v.apply(&tok[p * c..(p + 1) * c]));
        }
        let scale = 1.0 / (c as f32).sqrt();
        let mut attn_out = vec![0.0f32; n * c];
        let mut scores = vec![0.0f32; n];
        for i in 0..n {
            for j in 0..n {
                scores[j] = dot_product(&q[i * c..(i + 1) * c], &k[j * c..(j + 1) * c]) * scale;
            }
            softmax(&mut scores);
            for j in 0..n {
                let s = scores[j];
                for ch in 0..c {
                    attn_out[i * c + ch] += s * v[j * c + ch];
                }
            }
        }
        // out proj + residual (back to NCHW, add to x)
        let mut y = x.to_vec();
        for p in 0..n {
            let o = self.o.apply(&attn_out[p * c..(p + 1) * c]);
            for ch in 0..c {
                y[ch * n + p] += o[ch];
            }
        }
        y
    }
}

pub struct FluxVae {
    conv_in: ConvW,
    mid_res0: ResnetW,
    mid_attn: VaeAttn,
    mid_res1: ResnetW,
    // up_blocks: (resnets, optional upsampler conv)
    up: Vec<(Vec<ResnetW>, Option<ConvW>)>,
    norm_out_w: Vec<f32>,
    norm_out_b: Vec<f32>,
    conv_out: ConvW,
    norm_out_groups_c: usize,
}

impl FluxVae {
    pub fn load(knot_source: &str, knot: &KnotWeights) -> Result<Self, String> {
        let pre = "flux_vae_decoder";
        let conv_in = dequant_conv(knot_source, knot, &format!("{pre}_conv_in_weight"), &format!("{pre}_conv_in_bias"))?;
        let mid_res0 = ResnetW::load(knot_source, knot, &format!("{pre}_mid_block_resnets_0"))?;
        let mid_attn = VaeAttn::load(knot_source, knot, &format!("{pre}_mid_block_attentions_0"))?;
        let mid_res1 = ResnetW::load(knot_source, knot, &format!("{pre}_mid_block_resnets_1"))?;
        let mut up = Vec::new();
        for b in 0..4 {
            let mut resnets = Vec::new();
            for r in 0..3 {
                let prefix = format!("{pre}_up_blocks_{b}_resnets_{r}");
                resnets.push(ResnetW::load(knot_source, knot, &prefix)?);
            }
            let ups_name = format!("{pre}_up_blocks_{b}_upsamplers_0_conv_weight");
            let upsampler = if knot.metadata.contains_key(&ups_name) {
                Some(dequant_conv(
                    knot_source,
                    knot,
                    &ups_name,
                    &format!("{pre}_up_blocks_{b}_upsamplers_0_conv_bias"),
                )?)
            } else {
                None
            };
            up.push((resnets, upsampler));
        }
        let norm_out_w = fetch_f32(knot_source, knot, &format!("{pre}_conv_norm_out_weight"))?;
        let norm_out_b = fetch_f32(knot_source, knot, &format!("{pre}_conv_norm_out_bias"))?;
        let conv_out = dequant_conv(knot_source, knot, &format!("{pre}_conv_out_weight"), &format!("{pre}_conv_out_bias"))?;
        let norm_out_groups_c = norm_out_w.len();
        Ok(Self {
            conv_in,
            mid_res0,
            mid_attn,
            mid_res1,
            up,
            norm_out_w,
            norm_out_b,
            conv_out,
            norm_out_groups_c,
        })
    }

    /// Decode latents [16, lh, lw] to RGB u8 [3, lh*8, lw*8] interleaved RGB.
    pub fn decode(&self, latents: &[f32], lh: usize, lw: usize) -> Result<Vec<u8>, String> {
        // unscale: z = z/scaling + shift
        let mut z = latents.to_vec();
        for v in z.iter_mut() {
            *v = *v / VAE_SCALING + VAE_SHIFT;
        }
        let (mut h, mut w) = (lh, lw);
        let mut x = conv2d(&z, FLUX_LATENT_CHANNELS, h, w, &self.conv_in);
        let mut c = self.conv_in.out_c;
        // mid
        let (xn, cn) = self.mid_res0.forward(&x, c, h, w);
        x = xn;
        c = cn;
        x = self.mid_attn.forward(&x, c, h, w);
        let (xn, cn) = self.mid_res1.forward(&x, c, h, w);
        x = xn;
        c = cn;
        // up blocks
        for (resnets, upsampler) in self.up.iter() {
            for res in resnets {
                let (xn, cn) = res.forward(&x, c, h, w);
                x = xn;
                c = cn;
            }
            if let Some(ups) = upsampler {
                let (xu, nh, nw) = nearest_upsample(&x, c, h, w);
                h = nh;
                w = nw;
                x = conv2d(&xu, c, h, w, ups);
                c = ups.out_c;
            }
            if x.iter().any(|v| !v.is_finite()) {
                return Err("VAE up block produced non-finite values".to_string());
            }
        }
        // norm out + silu + conv_out
        group_norm_silu(&mut x, c, h, w, &self.norm_out_w, &self.norm_out_b, true);
        let _ = self.norm_out_groups_c;
        let rgb = conv2d(&x, c, h, w, &self.conv_out); // [3, h, w]
        let mut out = vec![0u8; h * w * 3];
        for y in 0..h {
            for xx in 0..w {
                for ch in 0..3 {
                    let v = rgb[ch * h * w + y * w + xx];
                    // diffusers: image = (sample/2 + 0.5).clamp(0,1)
                    let u = ((v * 0.5 + 0.5).clamp(0.0, 1.0) * 255.0).round() as u8;
                    out[(y * w + xx) * 3 + ch] = u;
                }
            }
        }
        if rgb.iter().any(|v| !v.is_finite()) {
            return Err("VAE conv_out produced non-finite values".to_string());
        }
        Ok(out)
    }

    /// DEBUG: decode an ALREADY-UNSCALED latent `z` [16, lh, lw] through the
    /// decoder graph and return RAW float channel-major RGB [3, lh*8, lw*8],
    /// skipping the (separately-verified) unscale constants and the final
    /// u8 clamp/quantize. For numeric cross-check against a diffusers Decoder.
    pub fn decode_raw_from_unscaled(
        &self,
        z: &[f32],
        lh: usize,
        lw: usize,
    ) -> Result<(Vec<f32>, usize, usize), String> {
        let (mut h, mut w) = (lh, lw);
        let mut x = conv2d(z, FLUX_LATENT_CHANNELS, h, w, &self.conv_in);
        let mut c = self.conv_in.out_c;
        let (xn, cn) = self.mid_res0.forward(&x, c, h, w);
        x = xn;
        c = cn;
        x = self.mid_attn.forward(&x, c, h, w);
        let (xn, cn) = self.mid_res1.forward(&x, c, h, w);
        x = xn;
        c = cn;
        for (resnets, upsampler) in self.up.iter() {
            for res in resnets {
                let (xn, cn) = res.forward(&x, c, h, w);
                x = xn;
                c = cn;
            }
            if let Some(ups) = upsampler {
                let (xu, nh, nw) = nearest_upsample(&x, c, h, w);
                h = nh;
                w = nw;
                x = conv2d(&xu, c, h, w, ups);
                c = ups.out_c;
            }
        }
        group_norm_silu(&mut x, c, h, w, &self.norm_out_w, &self.norm_out_b, true);
        let rgb = conv2d(&x, c, h, w, &self.conv_out); // [3, h, w]
        if rgb.iter().any(|v| !v.is_finite()) {
            return Err("VAE decode_raw produced non-finite values".to_string());
        }
        Ok((rgb, h, w))
    }
}

/// DEBUG: like `decode_raw_from_unscaled` but also returns named stage tensors
/// (conv_in, mid, up0..up3, norm_out, rgb) for stage-by-stage divergence
/// localization against a diffusers Decoder with forward hooks.
impl FluxVae {
    #[allow(clippy::type_complexity)]
    pub fn decode_raw_stages(
        &self,
        z: &[f32],
        lh: usize,
        lw: usize,
    ) -> Result<Vec<(String, Vec<f32>)>, String> {
        let (mut h, mut w) = (lh, lw);
        let mut stages: Vec<(String, Vec<f32>)> = Vec::new();
        let mut x = conv2d(z, FLUX_LATENT_CHANNELS, h, w, &self.conv_in);
        let mut c = self.conv_in.out_c;
        stages.push(("conv_in".to_string(), x.clone()));
        let (xn, cn) = self.mid_res0.forward(&x, c, h, w);
        x = xn;
        c = cn;
        stages.push(("mid_res0".to_string(), x.clone()));
        x = self.mid_attn.forward(&x, c, h, w);
        stages.push(("mid_attn".to_string(), x.clone()));
        let (xn, cn) = self.mid_res1.forward(&x, c, h, w);
        x = xn;
        c = cn;
        stages.push(("mid".to_string(), x.clone()));
        for (bi, (resnets, upsampler)) in self.up.iter().enumerate() {
            for res in resnets {
                let (xn, cn) = res.forward(&x, c, h, w);
                x = xn;
                c = cn;
            }
            if let Some(ups) = upsampler {
                let (xu, nh, nw) = nearest_upsample(&x, c, h, w);
                h = nh;
                w = nw;
                x = conv2d(&xu, c, h, w, ups);
                c = ups.out_c;
            }
            stages.push((format!("up{bi}"), x.clone()));
        }
        group_norm_silu(&mut x, c, h, w, &self.norm_out_w, &self.norm_out_b, true);
        stages.push(("norm_out".to_string(), x.clone()));
        let rgb = conv2d(&x, c, h, w, &self.conv_out);
        stages.push(("rgb".to_string(), rgb));
        Ok(stages)
    }
}

/// DEBUG: decode a deterministic latent through the FLUX VAE decoder graph and
/// dump raw float channel-major RGB for numeric cross-check against a diffusers
/// AutoencoderKL Decoder. The latent is the ALREADY-UNSCALED `z` (the reference
/// must feed the identical `z` directly to the decoder, bypassing scaling).
pub fn debug_vae_decode_raw(
    knot_source: &str,
    knot: &KnotWeights,
    lh: usize,
    lw: usize,
) -> Result<(Vec<f32>, usize, usize), String> {
    let vae = FluxVae::load(knot_source, knot)?;
    let z = debug_vae_latent(lh, lw);
    vae.decode_raw_from_unscaled(&z, lh, lw)
}

/// The deterministic VAE-debug latent z (seed 5) over [16, lh, lw].
pub fn debug_vae_latent(lh: usize, lw: usize) -> Vec<f32> {
    let n = FLUX_LATENT_CHANNELS * lh * lw;
    let mut z = vec![0.0f32; n];
    for i in 0..n {
        let a = ((i + 1) as f32) * 0.0007 + 5.0 * 0.013;
        z[i] = a.sin() * 0.8 + (a * 2.3).cos() * 0.2;
    }
    z
}

/// DEBUG: per-stage VAE decode dump for divergence localization.
pub fn debug_vae_decode_stages(
    knot_source: &str,
    knot: &KnotWeights,
    lh: usize,
    lw: usize,
) -> Result<Vec<(String, Vec<f32>)>, String> {
    let vae = FluxVae::load(knot_source, knot)?;
    let z = debug_vae_latent(lh, lw);
    vae.decode_raw_stages(&z, lh, lw)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn timestep_embedding_is_finite_and_sized() {
        let e = timestep_embedding(0.5, 256);
        assert_eq!(e.len(), 256);
        assert!(e.iter().all(|x| x.is_finite()));
    }

    #[test]
    fn rope_text_tokens_are_identity() {
        let r = RopeTable::build(2, 4, 4);
        // text token at pos 0 => cos=1 sin=0 => identity
        let mut h = vec![1.0f32; FLUX_DIT_HIDDEN];
        let before = h.clone();
        r.apply_token(&mut h, 0);
        for (a, b) in before.iter().zip(h.iter()) {
            assert!((a - b).abs() < 1e-5);
        }
    }

    #[test]
    fn rope_image_tokens_rotate() {
        let r = RopeTable::build(1, 4, 4);
        // an image token at a nonzero grid position should change the vector
        let mut h = vec![1.0f32; FLUX_DIT_HIDDEN];
        let before = h.clone();
        r.apply_token(&mut h, 1 + 5); // token after text, grid pos (1,1)
        let diff: f32 = before.iter().zip(h.iter()).map(|(a, b)| (a - b).abs()).sum();
        assert!(diff > 0.1, "expected rotation to change image token, diff={diff}");
    }

    /// Naive single-thread reference conv (the pre-optimization loop structure),
    /// kept verbatim here so the optimized `conv2d` can be diffed against it.
    fn conv2d_naive_ref(input: &[f32], in_c: usize, h: usize, w: usize, cw: &ConvW) -> Vec<f32> {
        let k = cw.k;
        let pad = (k - 1) / 2;
        let mut out = vec![0.0f32; cw.out_c * h * w];
        for oc in 0..cw.out_c {
            let bias = cw.b[oc];
            for oy in 0..h {
                for ox in 0..w {
                    let mut acc = bias;
                    for ic in 0..in_c {
                        for ky in 0..k {
                            let iy = oy as isize + ky as isize - pad as isize;
                            if iy < 0 || iy >= h as isize {
                                continue;
                            }
                            for kx in 0..k {
                                let ix = ox as isize + kx as isize - pad as isize;
                                if ix < 0 || ix >= w as isize {
                                    continue;
                                }
                                let iv = input[ic * h * w + iy as usize * w + ix as usize];
                                let wv = cw.w[((oc * cw.in_c + ic) * k + ky) * k + kx];
                                acc += iv * wv;
                            }
                        }
                    }
                    out[oc * h * w + oy * w + ox] = acc;
                }
            }
        }
        out
    }

    /// Serial reference for joint_attention (pre-parallelization loop).
    fn joint_attention_serial_ref(q: &[f32], k: &[f32], v: &[f32], tokens: usize) -> Vec<f32> {
        let mut out = vec![0.0f32; tokens * FLUX_DIT_HIDDEN];
        let scale = 1.0 / (FLUX_DIT_HEAD_DIM as f32).sqrt();
        let mut scores = vec![0.0f32; tokens];
        for head in 0..FLUX_DIT_HEADS {
            let ho = head * FLUX_DIT_HEAD_DIM;
            for ti in 0..tokens {
                let qs = ti * FLUX_DIT_HIDDEN + ho;
                let qh = &q[qs..qs + FLUX_DIT_HEAD_DIM];
                for tj in 0..tokens {
                    let ks = tj * FLUX_DIT_HIDDEN + ho;
                    scores[tj] = dot_product(qh, &k[ks..ks + FLUX_DIT_HEAD_DIM]) * scale;
                }
                softmax(&mut scores);
                let os = ti * FLUX_DIT_HIDDEN + ho;
                for tj in 0..tokens {
                    let w = scores[tj];
                    let vs = tj * FLUX_DIT_HIDDEN + ho;
                    for d in 0..FLUX_DIT_HEAD_DIM {
                        out[os + d] += w * v[vs + d];
                    }
                }
            }
        }
        out
    }

    #[test]
    fn joint_attention_parallel_matches_serial_bit_identical() {
        let tokens = 19usize;
        let mut state: u64 = 0xD1B54A32D192ED03;
        let mut next = || {
            state = state.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407);
            (((state >> 33) as f32) / (u32::MAX as f32)) * 2.0 - 1.0
        };
        let n = tokens * FLUX_DIT_HIDDEN;
        let q: Vec<f32> = (0..n).map(|_| next()).collect();
        let k: Vec<f32> = (0..n).map(|_| next()).collect();
        let v: Vec<f32> = (0..n).map(|_| next()).collect();
        let opt = joint_attention(&q, &k, &v, tokens).expect("attn");
        let refv = joint_attention_serial_ref(&q, &k, &v, tokens);
        assert_eq!(opt.len(), refv.len());
        let mut max_rel = 0.0f32;
        for (a, b) in opt.iter().zip(refv.iter()) {
            let rel = (a - b).abs() / b.abs().max(1e-6);
            max_rel = max_rel.max(rel);
        }
        assert_eq!(opt, refv, "parallel attn != serial (max_rel={max_rel})");
        assert!(max_rel < 1e-4, "rel error too high: {max_rel}");
    }

    #[test]
    #[ignore] // timing bench, run with --ignored
    fn conv2d_speedup_bench() {
        use std::time::Instant;
        // A representative big VAE conv: 128->128, 3x3, at 256x256.
        let (in_c, out_c, h, w, k) = (128usize, 128usize, 256usize, 256usize, 3usize);
        let input: Vec<f32> = (0..in_c * h * w).map(|i| ((i % 97) as f32) / 97.0).collect();
        let weight: Vec<f32> =
            (0..out_c * in_c * k * k).map(|i| ((i % 53) as f32) / 53.0 - 0.5).collect();
        let bias: Vec<f32> = (0..out_c).map(|i| (i as f32) * 1e-3).collect();
        let cw = ConvW { w: weight, b: bias, out_c, in_c, k };
        let t0 = Instant::now();
        let opt = conv2d(&input, in_c, h, w, &cw);
        let dt_opt = t0.elapsed();
        let t1 = Instant::now();
        let refv = conv2d_naive_ref(&input, in_c, h, w, &cw);
        let dt_ref = t1.elapsed();
        assert_eq!(opt, refv);
        eprintln!(
            "[conv2d bench 128x128 @256x256] naive={:?} optimized={:?} speedup={:.2}x",
            dt_ref,
            dt_opt,
            dt_ref.as_secs_f64() / dt_opt.as_secs_f64()
        );
    }

    #[test]
    fn conv2d_optimized_matches_naive_bit_identical() {
        // Deterministic pseudo-random input/weights (LCG) across a few conv
        // shapes that occur in the VAE decoder (3x3 same-pad, varied channels).
        let mut state: u64 = 0x9E3779B97F4A7C15;
        let mut next = || {
            state = state.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407);
            (((state >> 33) as f32) / (u32::MAX as f32)) * 2.0 - 1.0
        };
        for &(in_c, out_c, h, w, k) in &[
            (16usize, 32usize, 7usize, 5usize, 3usize),
            (32, 32, 8, 8, 3),
            (3, 16, 9, 9, 1),
            (64, 33, 6, 4, 3),
        ] {
            let input: Vec<f32> = (0..in_c * h * w).map(|_| next()).collect();
            let weight: Vec<f32> = (0..out_c * in_c * k * k).map(|_| next()).collect();
            let bias: Vec<f32> = (0..out_c).map(|_| next()).collect();
            let cw = ConvW { w: weight, b: bias, out_c, in_c, k };
            let opt = conv2d(&input, in_c, h, w, &cw);
            let refv = conv2d_naive_ref(&input, in_c, h, w, &cw);
            assert_eq!(opt.len(), refv.len());
            let mut max_abs = 0.0f32;
            let mut max_rel = 0.0f32;
            for (a, b) in opt.iter().zip(refv.iter()) {
                let abs = (a - b).abs();
                max_abs = max_abs.max(abs);
                let rel = abs / (b.abs().max(1e-6));
                max_rel = max_rel.max(rel);
            }
            // Order-preserving parallelism => expect EXACT bit-identity.
            assert_eq!(
                opt, refv,
                "shape {in_c}x{out_c}x{h}x{w}x{k}: opt != naive (max_abs={max_abs}, max_rel={max_rel})"
            );
            assert!(max_rel < 1e-4, "rel error too high: {max_rel}");
        }
    }

    #[test]
    fn schnell_sigmas_are_monotone_decreasing() {
        let s = flux_schnell_sigmas(4, 256);
        assert_eq!(s.len(), 5);
        for i in 1..s.len() {
            assert!(s[i] <= s[i - 1] + 1e-6);
        }
        assert!((s[0] - 1.0).abs() < 0.2);
        assert!(s[4].abs() < 1e-3);
    }
}
